-- Recorded from a live Plex Media Server (PMS 1.43.3, SFLIX) on 2026-07-22 — plex-safety rule 11.
-- Only the two tables the watched-flag reader touches. `parent_id` is load-bearing: episode ->
-- season -> show is how a marked season folds into the show ratingKey that the play-history source
-- and the library index are both keyed on. A hand-written approximation of this schema is what let
-- an episode-key bug through review once already.
CREATE TABLE "metadata_items" ("id" INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, "library_section_id" integer, "parent_id" integer, "metadata_type" integer, "guid" varchar(255), "media_item_count" integer, "title" varchar(255), "title_sort" varchar(255) COLLATE NOCASE, "original_title" varchar(255), "studio" varchar(255), "rating" float, "rating_count" integer, "tagline" varchar(255), "summary" text, "trivia" text, "quotes" text, "content_rating" varchar(255), "content_rating_age" integer, "index" integer, "absolute_index" integer, "duration" integer, "user_thumb_url" varchar(255), "user_art_url" varchar(255), "user_banner_url" varchar(255), "user_music_url" varchar(255), "user_fields" varchar(255), "tags_genre" varchar(255), "tags_collection" varchar(255), "tags_director" varchar(255), "tags_writer" varchar(255), "tags_star" varchar(255), "originally_available_at" dt_integer(8), "available_at" dt_integer(8), "expires_at" dt_integer(8), "refreshed_at" dt_integer(8), "year" integer, "added_at" dt_integer(8), "created_at" dt_integer(8), "updated_at" dt_integer(8), "deleted_at" dt_integer(8), "tags_country" varchar(255), "extra_data" varchar(255), "hash" varchar(255), "audience_rating" float, "changed_at" integer(8) DEFAULT 0, "resources_changed_at" integer(8) DEFAULT 0, 'remote' integer, 'edition_title' varchar(255), 'slug' varchar(255), 'user_clear_logo_url' varchar(255), 'is_adult' integer, 'metadata_agent_provider_group_id' integer, 'user_square_art_url' varchar(255));
CREATE TABLE "metadata_item_settings" ("id" INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL, "account_id" integer, "guid" varchar(255), "rating" float, "view_offset" integer, "view_count" integer, "last_viewed_at" dt_integer(8), "created_at" dt_integer(8), "updated_at" dt_integer(8), "skip_count" integer DEFAULT 0, "last_skipped_at" dt_integer(8) DEFAULT NULL, "changed_at" integer(8) DEFAULT 0, 'extra_data' varchar(255), 'last_rated_at' dt_integer(8));
